kernel_src="""

#include "kernel_operator.h"
#include "ca6k_00535_custom_tiling.h"

class KernelCa6k00535Custom {
public:
    __aicore__ inline KernelCa6k00535Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t rows, uint32_t cols,
                                uint32_t blockDim)
    {
        rows_ = rows;
        cols_ = cols;
        blockDim_ = blockDim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, rows_ * cols_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, rows_ * cols_);

        pipe_.InitBuffer(inBufX_, 1, rows_ * sizeof(float));
        pipe_.InitBuffer(outBufY_, 1, rows_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (rows_ == 0 || cols_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t colsPerBlock = (cols_ + blockDim_ - 1) / blockDim_;
        uint32_t startCol = blockIdx * colsPerBlock;
        uint32_t endCol = startCol + colsPerBlock;
        if (endCol > cols_) endCol = cols_;

        for (uint32_t col = startCol; col < endCol; col++) {
            // Copy entire column to local
            AscendC::LocalTensor<float> xLocal = inBufX_.Get<float>();
            AscendC::DataCopy(xLocal, xGm_[col * rows_], rows_);

            // Compute cumulative max sequentially
            AscendC::LocalTensor<float> yLocal = outBufY_.Get<float>();
            float curMax = -3.4028235e+38f;
            for (uint32_t i = 0; i < rows_; i++) {
                float val = xLocal(i);
                if (val > curMax) curMax = val;
                yLocal(i) = curMax;
            }

            // Copy result back to global
            AscendC::DataCopy(yGm_[col * rows_], yLocal, rows_);
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> inBufX_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> outBufY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t rows_ {0};
    uint32_t cols_ {0};
    uint32_t blockDim_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00535_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00535Custom op;
    op.Init(x, y, tiling_data.rows, tiling_data.cols, tiling_data.blockDim);
    op.Process();
}
